script.code:
const batchSignoffId = $workflow.input.batch_signoff_id;
const decisionMakerName = $workflow.input.decision_maker_name;
const batchAlerts = $workflow.input.batch_alerts;
if (!batchSignoffId) throw new Error('VALIDATION_ERROR: batch_signoff_id is required in batch mode');
if (!decisionMakerName) throw new Error('VALIDATION_ERROR: decision_maker_name is required');
if (!Array.isArray(batchAlerts) || batchAlerts.length === 0) throw new Error('VALIDATION_ERROR: batch_alerts must be a non-empty array');
return { batch_signoff_id: batchSignoffId, decision_maker_name: decisionMakerName, decision_timestamp: $workflow.input.decision_timestamp || '', alert_count: batchAlerts.length };

const alert = $alertItem;
const alertId = alert.alert_id || '';
const wasPulled = alert.was_pulled === true;
const humanActionStr = (alert.human_action || 'batch_approved').toLowerCase();
const correctionReason = alert.correction_reason || '';
const HUMAN_ACTION_MAP = { 'signed_agree': 0, 'override': 1, 'batch_approved': 2, 'confirm_low': 3, 'correct_upward': 4 };
const humanActionNum = HUMAN_ACTION_MAP[humanActionStr] !== undefined ? HUMAN_ACTION_MAP[humanActionStr] : 2;
if (!alertId) throw new Error('BATCH_ITEM_ERROR: alert_id missing at index ' + $alertItemIndex);
return { alert_id: alertId, was_pulled: wasPulled, human_action_number_id: humanActionNum, correction_reason: correctionReason };

const qr = $context.outputs.QueryEntityRecordsCurated_CheckBatchDecision;
const items = (qr && qr.content && Array.isArray(qr.content.value)) ? qr.content.value : (qr && qr.content && Array.isArray(qr.content.Value)) ? qr.content.Value : (Array.isArray(qr) ? qr : []);
return { exists: items.length > 0 };

const results = ($context.outputs.For_Each_BatchAlerts && Array.isArray($context.outputs.For_Each_BatchAlerts.results)) ? $context.outputs.For_Each_BatchAlerts.results : [];
let written = 0;
let skipped = 0;
for (let i = 0; i < results.length; i++) { const r = results[i]; if (r) { written += (r.written || 0); skipped += (r.skipped || 0); } }
return { records_written: written, records_skipped: skipped };

const alertId = $workflow.input.alert_id;
const humanAction = $workflow.input.human_action;
const decisionMakerName = $workflow.input.decision_maker_name;
const finalDisposition = $workflow.input.final_disposition;
const overrideReason = $workflow.input.override_reason;
if (!alertId) throw new Error('VALIDATION_ERROR: alert_id is required');
if (!humanAction || (humanAction !== 'signed_agree' && humanAction !== 'override')) throw new Error('VALIDATION_ERROR: human_action must be signed_agree or override');
if (humanAction === 'override' && (!overrideReason || overrideReason.trim() === '')) throw new Error('OVERRIDE_REASON_REQUIRED: override_reason is required when human_action is override');
if (!decisionMakerName) throw new Error('VALIDATION_ERROR: decision_maker_name is required');
if (!finalDisposition) throw new Error('VALIDATION_ERROR: final_disposition is required');
const RISK_TIER_MAP = { 'low': 0, 'medium': 1, 'high': 2 };
const ROUTE_MAP = { 'low_batch': 0, 'medium_signoff': 1, 'high_challenger': 2 };
const HUMAN_ACTION_MAP = { 'signed_agree': 0, 'override': 1 };
const DISPOSITION_MAP = { 'closed': 0, 'escalated': 1, 'sent_to_edd': 2 };
const finalTier = ($workflow.input.final_risk_tier || 'medium').toLowerCase();
const originalTier = ($workflow.input.original_proposed_tier || finalTier).toLowerCase();
const routeTaken = ($workflow.input.route_taken || 'medium_signoff').toLowerCase();
const disp = finalDisposition.toLowerCase();
const tierWasForced = $workflow.input.tier_was_forced === true;
const challengerOutcomeInput = ($workflow.input.challenger_outcome || '').toLowerCase();
const CHALLENGER_OUTCOME_MAP = { '': 0, 'not_applicable': 0, 'agreed': 1, 'disagreed': 2 };
const challengerOutcomeNumberId = CHALLENGER_OUTCOME_MAP[challengerOutcomeInput] !== undefined ? CHALLENGER_OUTCOME_MAP[challengerOutcomeInput] : 0;
return { final_risk_tier_number_id: RISK_TIER_MAP[finalTier] !== undefined ? RISK_TIER_MAP[finalTier] : 1, original_proposed_tier_number_id: RISK_TIER_MAP[originalTier] !== undefined ? RISK_TIER_MAP[originalTier] : 1, route_taken_number_id: ROUTE_MAP[routeTaken] !== undefined ? ROUTE_MAP[routeTaken] : 1, human_action_number_id: HUMAN_ACTION_MAP[humanAction], challenger_outcome_number_id: challengerOutcomeNumberId, final_disposition_number_id: DISPOSITION_MAP[disp] !== undefined ? DISPOSITION_MAP[disp] : 0, tier_was_forced: tierWasForced };

const qr = $context.outputs.QueryEntityRecordsCurated_CheckDecision;
const items = (qr && qr.content && Array.isArray(qr.content.value)) ? qr.content.value : (qr && qr.content && Array.isArray(qr.content.Value)) ? qr.content.Value : (Array.isArray(qr) ? qr : []);
const exists = items.length > 0;
const record_id = exists ? (items[0].Id !== undefined ? items[0].Id : items[0].id !== undefined ? items[0].id : '') : '';
return { exists, record_id };

const cr = $context.outputs.CreateEntityRecordCurated_DecisionRecord;
const id = (cr && cr.content && cr.content.Id !== undefined) ? cr.content.Id : (cr && cr.content && cr.content.id !== undefined) ? cr.content.id : '';
return id;

const TRIGGER_KIND_MAP = { 'sanctions': 0, 'pep': 1, 'structuring': 2, 'jurisdiction': 3, 'watchlist': 4 };
const qr = $context.outputs.QueryEntityRecordsCurated_ExistingTriggers;
const existing = (qr && qr.content && Array.isArray(qr.content.value)) ? qr.content.value : (qr && qr.content && Array.isArray(qr.content.Value)) ? qr.content.Value : (Array.isArray(qr) ? qr : []);
const existingKindIds = new Set(existing.map(function(r) { return r.TriggerKind !== undefined ? r.TriggerKind : r.triggerkind; }));
const redFlags = Array.isArray($workflow.input.red_flags) ? $workflow.input.red_flags : [];
const toInsert = [];
for (let i = 0; i < redFlags.length; i++) {
  const flag = redFlags[i];
  const kindId = TRIGGER_KIND_MAP[flag.kind];
  if (kindId !== undefined && !existingKindIds.has(kindId)) {
    toInsert.push({ kind_number_id: kindId, detail: flag.detail || '' });
    existingKindIds.add(kindId);
  }
}
return { triggers_to_insert: toInsert };
